import "./App.css";
import Navbar from "./component/Navbar";
import TextFrom from "./component/TextForm";
import React, { useState } from "react";
function App() {
  let toggleMode = () => {
    if (mode === 'light') {
      setMode('dark');
    } else {
      setMode('light');
    }
  };
  const [mode, setMode] = useState('light');
  return (
    <>
      <Navbar
        Title="Text Utiles"
        about="About Us"
        mode={mode}
        toggleMode={toggleMode}
      />
      <div className="container">
        <TextFrom heading="Enter Your Text To Analyse Below" />
      </div>
    </>
  );
}

export default App;
